   400→  // │                                    Auction Participation                                     │
   401→  // ================================================================================================
   402→
   403→  /// @inheritdoc IBaseAuction
   404→  /// @dev precondition - The auction for the asset must be live (i.e. started and not ended).
   405→  /// @dev precondition - The caller must have approved the contract to spend at least `assetOutAmount` amount of asset
   406→  /// out.
   407→  /// @dev precondition - The call must not be reentered.
   408→  /// @dev precondition - The bid USD value must be above the minimum auction size.
   409→  /// @dev precondition - The bid amount must be less than or equal to the available amount in the auction.
   410→  function bid(
   411→    address asset,
   412→    uint256 amount,
   413→    bytes calldata data
   414→  ) external whenNotPaused {
   415→    if (s_entered) {
   416→      revert Errors.ReentrantCall();
   417→    }
   418→    s_entered = true;
   419→
   420→    AssetParams memory assetParams = s_assetParams[asset];
   421→    uint256 auctionStart = s_auctionStarts[asset];
   422→
   423→    uint256 elapsedTime = block.timestamp - auctionStart;
   424→
   425→    if (auctionStart == 0 || elapsedTime > assetParams.auctionDuration) {
   426→      revert InvalidAuction(asset);
   427→    }
   428→
   429→    (uint256 assetPrice,,) = _getAssetPrice(asset, true);
   430→    uint256 bidUsdValue = (amount * assetPrice) / (10 ** assetParams.decimals);
   431→    uint88 minBidUsdValue = s_minBidUsdValue;
   432→
   433→    if (bidUsdValue < minBidUsdValue) {
   434→      revert BidValueTooLow(bidUsdValue, minBidUsdValue);
   435→    }
   436→
   437→    uint256 availableBalance = IERC20(asset).balanceOf(address(this));
   438→    if (amount > availableBalance) {
   439→      revert BidAmountTooHigh(amount, availableBalance);
   440→    }
   441→
   442→    uint256 assetOutAmount = _getAssetOutAmount(assetParams, assetPrice, amount, elapsedTime, true);
   443→
   444→    IERC20(asset).safeTransfer(msg.sender, amount);
   445→
   446→    address assetOut = s_assetOut;
